parameters.jsCode:
const video = $input.first().json;
const defaultLang = video?.snippet?.defaultLanguage || $('Configuration').first().json.default_language || 'en';
const nameToCode = $('Configuration').first().json.target_languages || {};
const entries = Object.entries(nameToCode).filter(([, code]) => code !== defaultLang);
const languages = entries.map(([name]) => name);
const keys = Object.fromEntries(entries);
return [{ json: { defaultLang, languages, keys } }];

parameters.text:
=Translate the YouTube video metadata whose default language is {{ $json.defaultLang }} into these languages: {{ $json.languages }}.

Use exactly these language keys in the output JSON: {{ JSON.stringify($json.keys) }}

Title: {{ $('Fetch video information').item.json.snippet.title }}

Description: {{ $('Fetch video information').item.json.snippet.description }}

Return ONLY a JSON object. Each key is a language code, each value is an object with a translated "title" and "description". Do not translate the default language. Keep line breaks and meaning faithful.

parameters.jsonBody:
={{ {
  id: $('Fetch video information').item.json.id,
  snippet: {
    defaultLanguage: $('Prepare target languages').item.json.defaultLang,
    title: $('Fetch video information').item.json.snippet.title,
    description: $('Fetch video information').item.json.snippet.description,
    categoryId: $('Fetch video information').item.json.snippet.categoryId,
    tags: $('Fetch video information').item.json.snippet.tags
  },
  localizations: $json.output
} }}
